from blake3 import blake3
from collections.abc import Iterator
from copy import copy, deepcopy
from typing import Any, Final, Optional

LANES: Final[int] = 1024
LANE_BYTES: Final[int] = 2
LANE_MODULUS: Final[int] = 2 ** (LANE_BYTES * 8)
PREVIEW_BYTES: Final[int] = 8
STATE_BYTES: Final[int] = LANES * LANE_BYTES

class LtLane:
	def __init__(self, value: Optional[int] = None):
		value = value if value is not None else 0
		self.__value: Final[int] = value % LANE_MODULUS

	@staticmethod
	def from_bytes(value: bytes) -> 'LtLane':
		if len(value) != LANE_BYTES:
			raise ValueError(f'Expected {LANE_BYTES} bytes, got {len(value)}')
		return LtLane(int.from_bytes(value, byteorder='little'))

	def to_bytes(self) -> bytes:
		return self.__value.to_bytes(LANE_BYTES, byteorder='little')

	def __add__(self, other: Any) -> 'LtLane':
		if isinstance(other, LtLane):
			return LtLane(self.__value + other.__value)
		elif isinstance(other, int):
			return LtLane(self.__value + other)
		else:
			raise TypeError(f'Expected type `LtLane | int`, got `{type(other)}`')
	def __sub__(self, other: Any) -> 'LtLane':
		if isinstance(other, LtLane):
			return LtLane(self.__value - other.__value)
		elif isinstance(other, int):
			return LtLane(self.__value - other)
		else:
			raise TypeError(f'Expected type `LtLane | int`, got `{type(other)}`')
	def __iadd__(self, other: Any):
		return NotImplemented
	def __isub__(self, other: Any):
		return NotImplemented

	def __bytes__(self) -> bytes:
		return self.to_bytes()
	def __copy__(self) -> 'LtLane':
		return LtLane(self.__value)
	def __deepcopy__(self, memo: dict) -> 'LtLane':
		return LtLane(self.__value)
	def __eq__(self, other: Any) -> bool:
		if isinstance(other, LtLane):
			return self.__value == other.__value
		elif isinstance(other, int):
			return self.__value == other
		else:
			return NotImplemented
	def __hash__(self) -> int:
		return hash(self.__value)
	def __repr__(self) -> str:
		return str(self)
	def __str__(self) -> str:
		preview = self.to_bytes().hex()
		return f'LtLane({preview})'

class LtHash:
	__hash__ = None

	def __init__(self, state: Optional[list[LtLane]] = None):
		state = state if state is not None else [LtLane()] * LANES
		if len(state) != LANES:
			raise ValueError(f'Expected {LANES} lanes, got {len(state)}')

		self.__state = state

	@property
	def state(self) -> list[LtLane]:
		return copy(self.__state)

	@staticmethod
	def from_bytes(state: bytes) -> 'LtHash':
		if len(state) != STATE_BYTES:
			raise ValueError(f'Expected {STATE_BYTES} bytes, got {len(state)}')

		ls = [LtLane.from_bytes(state[i * LANE_BYTES : (i + 1) * LANE_BYTES]) for i in range(LANES)]
		return LtHash(ls)

	def to_bytes(self) -> bytes:
		return b''.join(lane.to_bytes() for lane in self.__state)

	def add(self, other: bytes):
		digest = blake3(other).digest(length=STATE_BYTES)
		for i in range(LANES):
			self.__state[i] += LtLane.from_bytes(digest[i * LANE_BYTES : (i + 1) * LANE_BYTES])
	def clear(self):
		self.__state = [LtLane()] * LANES
	def remove(self, other: bytes):
		digest = blake3(other).digest(length=STATE_BYTES)
		for i in range(LANES):
			self.__state[i] -= LtLane.from_bytes(digest[i * LANE_BYTES : (i + 1) * LANE_BYTES])

	def __bytes__(self) -> bytes:
		return self.to_bytes()
	def __copy__(self) -> 'LtHash':
		return LtHash(list(self.__state))
	def __deepcopy__(self, memo: dict) -> 'LtHash':
		return LtHash([deepcopy(lane, memo) for lane in self.__state])
	def __eq__(self, other: Any) -> bool:
		if isinstance(other, LtHash):
			return self.__state == other.__state
		else:
			return NotImplemented
	def __repr__(self) -> str:
		return str(self)
	def __str__(self) -> str:
		preview = self.to_bytes()[:PREVIEW_BYTES].hex()
		return f'LtHash({preview}...)'

class LtSet:
	__hash__ = None

	def __init__(self, *args: bytes):
		self.__hash = LtHash()
		self.__hashMemoized = None
		self.__set: set[bytes] = set()
		self.__setMemoized = None

		for argument in args:
			self.__hash.add(argument)
			self.__set.add(argument)

	@property
	def hash(self) -> LtHash:
		if self.__hashMemoized is None:
			self.__hashMemoized = copy(self.__hash)
		return self.__hashMemoized
	@property
	def set(self) -> frozenset[bytes]:
		if self.__setMemoized is None:
			self.__setMemoized = frozenset(self.__set)
		return self.__setMemoized

	def add(self, item: bytes):
		if item not in self.__set:
			self.__set.add(item)
			self.__setMemoized = None
			self.__hash.add(item)
			self.__hashMemoized = None
	def clear(self):
		self.__set.clear()
		self.__setMemoized = None
		self.__hash.clear()
		self.__hashMemoized = None
	def discard(self, item: bytes):
		if item in self.__set:
			self.__set.remove(item)
			self.__setMemoized = None
			self.__hash.remove(item)
			self.__hashMemoized = None

	def __bytes__(self) -> bytes:
		return self.__hash.to_bytes()
	def __contains__(self, item: Any) -> bool:
		return item in self.__set
	def __copy__(self) -> 'LtSet':
		new = LtSet.__new__(LtSet)
		new.__hash = copy(self.__hash)
		new.__hashMemoized = None
		new.__set = copy(self.__set)
		new.__setMemoized = None
		return new
	def __deepcopy__(self, memo: dict) -> 'LtSet':
		new = LtSet.__new__(LtSet)
		new.__hash = deepcopy(self.__hash, memo)
		new.__hashMemoized = None
		new.__set = deepcopy(self.__set, memo)
		new.__setMemoized = None
		return new
	def __eq__(self, other: Any) -> bool:
		if isinstance(other, LtSet):
			return self.__hash == other.__hash
		elif isinstance(other, LtHash):
			return self.__hash == other
		else:
			return NotImplemented
	def __iter__(self) -> Iterator:
		if self.__setMemoized is None:
			self.__setMemoized = frozenset(self.__set)
		return iter(self.__setMemoized)
	def __len__(self) -> int:
		return len(self.__set)
	def __repr__(self) -> str:
		return str(self)
	def __str__(self) -> str:
		preview = self.__hash.to_bytes()[:PREVIEW_BYTES].hex()
		return f'LtSet({preview}...)'
